const AUTH_URL="https://ootloyfutihvupfforrv.supabase.co";
const AUTH_KEY="sb_publishable_ppRwsR2EfF1Xx4ZTiQsSCw__w7tOLkG";
const AUTH_STORAGE="egshop_session";
function session(){try{return JSON.parse(localStorage.getItem(AUTH_STORAGE)||"null")}catch{return null}}
function save(value){if(value?.access_token)localStorage.setItem(AUTH_STORAGE,JSON.stringify(value))}
function parse(text){try{return text?JSON.parse(text):null}catch{return null}}
async function request(path,options={}){const response=await fetch(`${AUTH_URL}${path}`,{...options,headers:{apikey:AUTH_KEY,Authorization:`Bearer ${session()?.access_token||AUTH_KEY}`,"Content-Type":"application/json",...options.headers}});const data=parse(await response.text());if(!response.ok){const raw=data?.msg||data?.message||data?.error_description||data?.error||"";if(/invalid login credentials/i.test(raw))throw new Error("E-poçt və ya şifrə yanlışdır.");if(/email not confirmed/i.test(raw))throw new Error("Əvvəlcə e-poçt ünvanınızı təsdiqləyin.");if(/already registered/i.test(raw))throw new Error("Bu e-poçtla artıq hesab yaradılıb.");throw new Error(raw||"Əməliyyat baş tutmadı.")}return data}
function validatePassword(value){if(!/^(?=.*[A-Za-z])(?=.*\d).{8,}$/.test(value))throw new Error("Şifrə ən azı 8 simvol, bir hərf və bir rəqəm içərməlidir.")}
function dialogParts(){return{dialog:document.querySelector("#accountDialog"),content:document.querySelector("#accountContent")}}
function showAccount(){const{dialog,content}=dialogParts(),user=session()?.user;if(!dialog||!content)return;content.replaceChildren();const kicker=document.createElement("span");kicker.className="dialog-kicker";kicker.textContent="Hesabım";const title=document.createElement("h2");title.textContent=user?.email||"EG Shop hesabı";const description=document.createElement("p");description.textContent="Hesabınız aktivdir.";const logout=document.createElement("button");logout.className="form-submit";logout.textContent="Çıxış et";logout.addEventListener("click",async()=>{try{await request("/auth/v1/logout",{method:"POST"})}catch{}localStorage.removeItem(AUTH_STORAGE);location.reload()});content.append(kicker,title,description,logout);dialog.showModal()}
function showAuth(){const{dialog,content}=dialogParts();if(!dialog||!content)return;content.innerHTML=`<span class="dialog-kicker">EG Shop</span><h2 id="authV2Title">Hesabınıza daxil olun</h2><div class="auth-v2-tabs"><button type="button" class="active" data-mode="login">Giriş</button><button type="button" data-mode="register">Qeydiyyat</button></div><form id="authV2Form" data-mode="login"><div data-register-fields hidden><label>Ad və soyad<input name="full_name" maxlength="100" autocomplete="name"></label><label>Telefon<input name="phone" type="tel" autocomplete="tel" placeholder="+994 50 000 00 00"></label></div><label>E-poçt<input name="email" type="email" autocomplete="email" required></label><label>Şifrə<span class="auth-v2-password"><input name="password" type="password" minlength="8" autocomplete="current-password" required><button type="button" data-toggle-password>Göstər</button></span></label><div data-register-fields hidden><label>Şifrəni təkrarla<input name="password_confirm" type="password" minlength="8" autocomplete="new-password"></label><label class="auth-v2-terms"><input name="terms" type="checkbox"><span>İstifadə şərtləri və məxfilik siyasətini qəbul edirəm.</span></label></div><button class="auth-v2-link" type="button" data-forgot>Şifrəni unutmusunuz?</button><button class="form-submit" type="submit">Giriş et</button><p class="form-message" data-auth-message></p></form>`;const form=content.querySelector("#authV2Form"),message=content.querySelector("[data-auth-message]");content.querySelectorAll("[data-mode]").forEach(tab=>tab.addEventListener("click",()=>{const register=tab.dataset.mode==="register";form.dataset.mode=tab.dataset.mode;content.querySelectorAll("[data-mode]").forEach(item=>item.classList.toggle("active",item===tab));content.querySelectorAll("[data-register-fields]").forEach(item=>item.hidden=!register);content.querySelector("#authV2Title").textContent=register?"Yeni hesab yaradın":"Hesabınıza daxil olun";form.querySelector(".form-submit").textContent=register?"Qeydiyyatdan keç":"Giriş et";form.elements.full_name.required=register;form.elements.phone.required=register;form.elements.password_confirm.required=register;content.querySelector("[data-forgot]").hidden=register;message.textContent=""}));content.querySelector("[data-toggle-password]").addEventListener("click",event=>{const input=form.elements.password;input.type=input.type==="password"?"text":"password";event.currentTarget.textContent=input.type==="password"?"Göstər":"Gizlət"});content.querySelector("[data-forgot]").addEventListener("click",async()=>{try{const email=form.elements.email.value.trim().toLowerCase();if(!email)throw new Error("Əvvəlcə e-poçt ünvanınızı daxil edin.");await request(`/auth/v1/recover?redirect_to=${encodeURIComponent("https://egshop.az/?recovery=1")}`,{method:"POST",body:JSON.stringify({email})});message.className="form-message success";message.textContent="Şifrə yeniləmə linki e-poçtunuza göndərildi."}catch(error){message.textContent=error.message}});form.addEventListener("submit",async event=>{event.preventDefault();if(!form.reportValidity())return;const submit=form.querySelector(".form-submit");submit.disabled=true;message.className="form-message";message.textContent="Gözləyin...";try{const email=form.elements.email.value.trim().toLowerCase(),password=form.elements.password.value;if(form.dataset.mode==="register"){validatePassword(password);if(password!==form.elements.password_confirm.value)throw new Error("Şifrələr eyni deyil.");if(!form.elements.terms.checked)throw new Error("İstifadə şərtlərini qəbul edin.");const phone=form.elements.phone.value.replace(/[^\d+]/g,"");if(phone.length<9)throw new Error("Telefon nömrəsini düzgün daxil edin.");const result=await request(`/auth/v1/signup?redirect_to=${encodeURIComponent("https://egshop.az")}`,{method:"POST",body:JSON.stringify({email,password,data:{full_name:form.elements.full_name.value.trim(),phone}})});save(result);message.className="form-message success";message.textContent="Qeydiyyat tamamlandı. E-poçtunuzu təsdiqləyin."}else{const result=await request("/auth/v1/token?grant_type=password",{method:"POST",body:JSON.stringify({email,password})});save(result);location.reload()}}catch(error){message.textContent=error.message}finally{submit.disabled=false}});dialog.showModal()}
document.addEventListener("click",event=>{if(!event.target.closest("[data-auth]"))return;event.preventDefault();event.stopImmediatePropagation();session()?.user?showAccount():showAuth()},true);
